SELECT molecular_weight
FROM chemical_compounds
WHERE molecular_weight = (SELECT MAX(molecular_weight) FROM chemical_compounds);

SELECT molecular_weight
FROM chemical_compounds
ORDER BY molecular_weight DESC;

SELECT molecular_formula, MAX(retention_time) AS max_retention_time
FROM chemical_compounds
GROUP BY molecular_formula;

SELECT DISTINCT RTRIM(molecular_formula) AS trimmed_molecular_formula
FROM chemical_compounds
WHERE chain_length > 3;
